// src/utils/security.js
import CryptoJS from 'crypto-js';
import { Platform } from 'react-native';
import * as Keychain from 'react-native-keychain';

class SecurityManager {
  constructor() {
    this._sessionKey = null;
    this._tokenTimestamp = null;
  }

  async initialize() {
    try {
      this._sessionKey = this._generateSessionKey();
      this._tokenTimestamp = Date.now();
      await this._storeSessionKey(this._sessionKey);
      return true;
    } catch (error) {
      console.error('[SecurityManager] Initialization failed:', error);
      throw new PaymentError(
        ERROR_CODES.ENCRYPTION_ERROR,
        'Failed to initialize security module'
      );
    }
  }

  _generateSessionKey() {
    const randomBytes = CryptoJS.lib.WordArray.random(32);
    return randomBytes.toString(CryptoJS.enc.Hex);
  }

  async _storeSessionKey(key) {
    await Keychain.setGenericPassword('payment_session', key, {
      service: 'com.yourapp.payment',
      accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
    });
  }

  async _retrieveSessionKey() {
    const credentials = await Keychain.getGenericPassword({
      service: 'com.yourapp.payment',
    });
    return credentials ? credentials.password : null;
  }

  encryptSensitiveData(data) {
    if (!this._sessionKey) {
      throw new PaymentError(
        ERROR_CODES.ENCRYPTION_ERROR,
        'Security module not initialized'
      );
    }

    if (this._isTokenExpired()) {
      throw new PaymentError(
        ERROR_CODES.TOKEN_EXPIRED,
        'Session token expired, re-initialization required'
      );
    }

    try {
      const iv = CryptoJS.lib.WordArray.random(16);
      const encrypted = CryptoJS.AES.encrypt(
        JSON.stringify(data),
        CryptoJS.enc.Hex.parse(this._sessionKey),
        {
          iv: iv,
          mode: CryptoJS.mode.GCM || CryptoJS.mode.CBC,
          padding: CryptoJS.pad.Pkcs7,
        }
      );

      return {
        ciphertext: encrypted.ciphertext.toString(CryptoJS.enc.Base64),
        iv: iv.toString(CryptoJS.enc.Base64),
        timestamp: Date.now(),
      };
    } catch (error) {
      throw new PaymentError(
        ERROR_CODES.ENCRYPTION_ERROR,
        'Data encryption failed'
      );
    }
  }

  decryptSensitiveData(encryptedPayload) {
    if (!this._sessionKey) {
      throw new PaymentError(
        ERROR_CODES.ENCRYPTION_ERROR,
        'Security module not initialized'
      );
    }

    try {
      const iv = CryptoJS.enc.Base64.parse(encryptedPayload.iv);
      const ciphertext = CryptoJS.enc.Base64.parse(encryptedPayload.ciphertext);

      const cipherParams = CryptoJS.lib.CipherParams.create({
        ciphertext: ciphertext,
      });

      const decrypted = CryptoJS.AES.decrypt(
        cipherParams,
        CryptoJS.enc.Hex.parse(this._sessionKey),
        {
          iv: iv,
          mode: CryptoJS.mode.GCM || CryptoJS.mode.CBC,
          padding: CryptoJS.pad.Pkcs7,
        }
      );

      return JSON.parse(decrypted.toString(CryptoJS.enc.Utf8));
    } catch (error) {
      throw new PaymentError(
        ERROR_CODES.ENCRYPTION_ERROR,
        'Data decryption failed'
      );
    }
  }

  _isTokenExpired() {
    if (!this._tokenTimestamp) return true;
    return (
      Date.now() - this._tokenTimestamp >
      PAYMENT_CONFIG.security.tokenExpiryMs
    );
  }

  sanitizeForLogging(data) {
    if (!data || typeof data !== 'object') return data;

    const sensitiveFields = [
      'cardNumber',
      'cvv',
      'cvc',
      'expiry',
      'expiryDate',
      'pin',
      'password',
      'token',
      'secret',
      'privateKey',
      'accountNumber',
      'routingNumber',
      'ssn',
    ];

    const sanitized = { ...data };
    for (const field of sensitiveFields) {
      if (sanitized[field]) {
        const value = String(sanitized[field]);
        sanitized[field] = value.length > 4
          ? `****${value.slice(-4)}`
          : '****';
      }
    }
    return sanitized;
  }

  generateIdempotencyKey() {
    const timestamp = Date.now().toString(36);
    const random = CryptoJS.lib.WordArray.random(16).toString(CryptoJS.enc.Hex);
    return `${Platform.OS}_${timestamp}_${random}`;
  }

  async clearSession() {
    this._sessionKey = null;
    this._tokenTimestamp = null;
    await Keychain.resetGenericPassword({ service: 'com.yourapp.payment' });
  }

  async refreshSession() {
    await this.clearSession();
    await this.initialize();
  }
}

export const securityManager = new SecurityManager();

