// src/utils/PaymentError.js
export class PaymentError extends Error {
  constructor(code, message, details = null, recoverable = false) {
    super(message);
    this.name = 'PaymentError';
    this.code = code;
    this.details = details;
    this.recoverable = recoverable;
    this.timestamp = new Date().toISOString();
  }

  toJSON() {
    return {
      name: this.name,
      code: this.code,
      message: this.message,
      details: this.details,
      recoverable: this.recoverable,
      timestamp: this.timestamp,
    };
  }

  static fromNativeError(nativeError, provider) {
    const errorMap = {
      apple_pay: {
        1: { code: ERROR_CODES.USER_CANCELLED, recoverable: false },
        2: { code: ERROR_CODES.PAYMENT_FAILED, recoverable: true },
        3: { code: ERROR_CODES.NETWORK_ERROR, recoverable: true },
      },
      google_pay: {
        8: { code: ERROR_CODES.USER_CANCELLED, recoverable: false },
        10: { code: ERROR_CODES.PROVIDER_UNAVAILABLE, recoverable: false },
        15: { code: ERROR_CODES.PAYMENT_FAILED, recoverable: true },
      },
      in_app_purchase: {
        E_USER_CANCELLED: { code: ERROR_CODES.USER_CANCELLED, recoverable: false },
        E_ITEM_UNAVAILABLE: { code: ERROR_CODES.PRODUCT_NOT_FOUND, recoverable: false },
        E_ALREADY_OWNED: { code: ERROR_CODES.DUPLICATE_PURCHASE, recoverable: false },
        E_NETWORK_ERROR: { code: ERROR_CODES.NETWORK_ERROR, recoverable: true },
        E_DEFERRED_PAYMENT: { code: ERROR_CODES.PURCHASE_PENDING, recoverable: false },
      },
    };

    const providerErrors = errorMap[provider] || {};
    const errorCode = nativeError.code || nativeError.responseCode;
    const mapped = providerErrors[errorCode];

    if (mapped) {
      return new PaymentError(
        mapped.code,
        nativeError.message || 'Payment error occurred',
        { originalError: nativeError, provider },
        mapped.recoverable
      );
    }

    return new PaymentError(
      ERROR_CODES.PAYMENT_FAILED,
      nativeError.message || 'Unknown payment error',
      { originalError: nativeError, provider },
      false
    );
  }
}

